// Serialize a draft `MetricDef[]` to the source of `src/pts-generated.ts`. The catalog drift gate
// re-runs the generator and `git diff --exit-code`s this file, so the bytes must be reproducible:
// entries in a stable id order (set by generateCatalog), object keys in a fixed canonical order, and
// strings via JSON.stringify (double-quoted, matching Biome). The entry script then pipes the result
// through Biome so committed and re-generated bytes are byte-identical (design §3.6).
import type { MetricDef } from "../../src/metrics.ts";

const HEADER = `// AUTOGENERATED by \`bun run generate-catalog\` from src/pts-profiles/*. DO NOT EDIT.
// Regenerate after vendoring or bumping a profile; the catalog drift gate diffs this file against a
// fresh generator run. Curation (headline/label/dimension) is layered separately in pts-overrides.ts.`;

/** One MetricDef as an object literal with keys in canonical order. */
function serializeDef(def: MetricDef): string {
	const parts = [
		`id: ${JSON.stringify(def.id)}`,
		`dimension: ${JSON.stringify(def.dimension)}`,
		`unit: ${JSON.stringify(def.unit)}`,
		`direction: ${JSON.stringify(def.direction)}`,
		`headline: ${def.headline}`,
		`label: ${JSON.stringify(def.label)}`,
		`description: ${JSON.stringify(def.description)}`,
	];
	if (def.pts) {
		const pts = [`test: ${JSON.stringify(def.pts.test)}`];
		if (def.pts.description !== undefined)
			pts.push(`description: ${JSON.stringify(def.pts.description)}`);
		parts.push(`pts: { ${pts.join(", ")} }`);
	}
	if (def.sourceUrl !== undefined) parts.push(`sourceUrl: ${JSON.stringify(def.sourceUrl)}`);
	return `{ ${parts.join(", ")} }`;
}

/** The full `pts-generated.ts` source for a draft catalog (pre-Biome; the script formats it). */
export function serializeCatalog(defs: readonly MetricDef[]): string {
	const body = defs.map((def) => `\t${serializeDef(def)},`).join("\n");
	return `${HEADER}\nimport type { MetricDef } from "./metrics.ts";\n\nexport const ptsGenerated: MetricDef[] = [\n${body}\n];\n`;
}
